import xml.etree.ElementTree as ET
from xmlschema import validate

def read_and_validate(file):
    try:
        # parse the file
        tree = ET.parse(file)
        root = tree.getroot()
        
        # define your schema here, for example:
        schema = {
            "type": "object",
            "properties": {
                "name": {"type": "string"},
                "age": {"type": "number"}
            }
        }
      
        # validate the xml against the defined schema
        is_valid = validate(root, schema)
        
        if not is_valid:
            print("The XML file is invalid.")
        else:
            print("The XML file is valid.")
    
    except ET.ParseError as e:
        print("Invalid XML format", str(e))